from lxml import etree

def process_soap_request(soap_xml, dtd_file):
    # Load and parse the DTD
    with open(dtd_file, 'r') as dtd_f:
        dtd = etree.DTD(dtd_f)

    # Parse the SOAP XML
    parser = etree.XMLParser(dtd_validation=True)
    try:
        soap_doc = etree.fromstring(soap_xml, parser)
    except etree.XMLSyntaxError as e:
        raise ValueError("Invalid XML or DTD: " + str(e))

    # Validate the XML against the DTD
    if not dtd.validate(soap_doc):
        raise ValueError("XML does not conform to DTD")

    # Extract the SOAP body
    ns = {'soap': 'http://schemas.xmlsoap.org/soap/envelope/'}
    body_element = soap_doc.xpath('//soap:Body', namespaces=ns)
    if len(body_element) == 0:
        raise ValueError("No SOAP Body found in the request")

    # Assuming a single body element
    return etree.tostring(body_element[0], pretty_print=True)

